from your_module import load_and_preprocess_data

# Mock configuration object
class MockConfig:
    def __init__(self):
        self.problem = MockProblem()
        self.algorithm = MockAlgorithm()
        self.pretrain = MockPretrain()
        self.exp_name = "test_exp"

class MockProblem:
    def __init__(self):
        self.exp_dir = "/tmp/test_exp"
        self.data = {
            'root': '/tmp/mock_data',
            'image_size': [320, 320],
            'simulated_kspace': True
        }
        self.model = {
            'total_lines': 320,
            'acceleration_ratio': 4,
            'mask_seed': 42,
            'pattern': 'random'
        }

class MockAlgorithm:
    def __init__(self):
        self.name = "test_algo"
        self.method = {
            'scheduler_config': {
                'num_steps': 10,
                'sigma_max': 100,
                'sigma_min': 0.01
            }
        }

class MockPretrain:
    def __init__(self):
        self.model = {
            'img_resolution': 320,
            'img_channels': 2,
            'model_type': 'DhariwalUNet'
        }

# Create a mock config and device
config = MockConfig()
device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')

# Load and preprocess data
result = load_and_preprocess_data(config, device)

# Access the loaded model and data
net = result['net']
observation = result['observation']
target = result['target']
